"""PipelineExecutor — Mantis 기본 Executor 구현.

Phase 파이프라인 기반:
  PREPARE (1회) → [RESOLVE → ACT → OBSERVE] × N → cleanup (finally)

모델만 넣으면 돌아간다. 나머지는 꽂으면 자동 활성화.
"""

from __future__ import annotations

import logging
import uuid
from dataclasses import dataclass
from typing import Any, AsyncIterator

from mantis.context.conversation import ConversationContext
from mantis.exceptions import LLMError
from mantis.executor.protocol import ExecutionContext
from mantis.executor.phases.prepare import DefaultPrepare
from mantis.executor.phases.resolve import DefaultResolve
from mantis.executor.phases.act import DefaultAct
from mantis.executor.phases.observe import DefaultObserve
from mantis.middleware.base import BaseMiddleware, Middleware, RunContext
from mantis.tools.decorator import ToolSpec
from mantis.tools.registry import ToolRegistry

logger = logging.getLogger(__name__)

MAX_ITERATIONS = 50


@dataclass
class PhaseConfig:
    """Phase 교체 설정."""

    prepare: Any | None = None
    resolve: Any | None = None
    act: Any | None = None
    observe: Any | None = None


class PipelineExecutor:
    """Mantis 기본 Executor — Phase 파이프라인 기반.

    모델만 넣으면 돌아간다. 나머지는 꽂으면 자동 활성화.
    """

    def __init__(
        self,
        model: Any,  # LLMProvider
        *,
        name: str = "mantis",
        tools: list[Any] | ToolRegistry | None = None,
        search: Any | None = None,     # SearchProvider
        sandbox: Any | None = None,    # SandboxProvider
        workflows: Any | None = None,  # WorkflowStore
        state: Any | None = None,      # StateStore
        system_prompt: str = "",
        middlewares: list[Middleware | BaseMiddleware] | None = None,
        phases: PhaseConfig | None = None,
        max_iterations: int = MAX_ITERATIONS,
    ):
        self.name = name
        self.model = model
        self.system_prompt = system_prompt
        self.max_iterations = max_iterations

        # Provider
        self.search = search
        self.sandbox = sandbox
        self.workflows = workflows
        self.state = state

        # 미들웨어
        self._middlewares: list[Middleware | BaseMiddleware] = list(middlewares or [])

        # ToolRegistry 구성
        self._registry = self._build_registry(tools)

        # 내장 도구 자동 등록
        self._register_builtins()

        # Phase 구성
        phases = phases or PhaseConfig()
        self._prepare = phases.prepare or DefaultPrepare()
        self._resolve = phases.resolve or DefaultResolve()
        self._act = phases.act or DefaultAct()
        self._observe = phases.observe or DefaultObserve()

        # ConversationContext
        self._context = ConversationContext(system_prompt=system_prompt)

    def _build_registry(self, tools: list[Any] | ToolRegistry | None) -> ToolRegistry:
        """tools 인자를 ToolRegistry로 변환."""
        if tools is None:
            return ToolRegistry()
        if isinstance(tools, ToolRegistry):
            return tools
        # list of @tool decorated functions or ToolSpec
        registry = ToolRegistry()
        for t in tools:
            if isinstance(t, ToolSpec):
                registry.register(t)
            elif hasattr(t, "_tool_spec"):
                registry.register(t._tool_spec)
            else:
                raise TypeError(
                    f"tools에 넣을 수 없는 타입: {type(t)}. "
                    "@tool 데코레이터를 붙이거나 ToolSpec을 전달하세요."
                )
        return registry

    def _register_builtins(self) -> None:
        """Provider에 따라 내장 도구를 자동 등록."""
        # search → search_tools, list_tools
        try:
            from mantis.tools.builtins import make_builtin_tools
            for spec in make_builtin_tools(
                registry=self._registry,
                search=self.search,
                sandbox=self.sandbox,
                workflows=self.workflows,
            ):
                self._registry.register(spec, source="builtin")
        except ImportError:
            pass

    @property
    def tool_registry(self) -> ToolRegistry:
        return self._registry

    @property
    def context(self) -> ConversationContext:
        return self._context

    # ─── 핵심 루프 ───

    async def _run_loop(
        self,
        user_input: str,
        session_id: str | None = None,
        *,
        model: Any | None = None,
        context: ConversationContext | None = None,
        extra_tools: list[Any] | None = None,
        flow: Any | None = None,
    ) -> AsyncIterator[dict]:
        """Phase 기반 핵심 루프.

        PREPARE (1회) → [RESOLVE → ACT → OBSERVE] × N → cleanup

        Args:
            model: 이번 호출에서만 사용할 LLM (None이면 생성자 모델).
            context: 미리 시딩된 ConversationContext (None이면 내부 컨텍스트).
            extra_tools: 이번 호출에만 추가할 도구 목록.
            flow: FlowState — 있으면 플로우 모드로 실행.
        """
        session_id = session_id or str(uuid.uuid4())
        effective_model = model or self.model
        effective_context = context or self._context

        # extra_tools 세션 스코프 등록
        if extra_tools:
            for t in extra_tools:
                spec = t if isinstance(t, ToolSpec) else getattr(t, "_tool_spec", None)
                if spec:
                    self._registry.register(spec, source="extra", session_id=session_id)

        ctx = ExecutionContext(
            session_id=session_id,
            run_ctx=RunContext(
                session_id=session_id,
                agent_name=self.name,
                last_user_message=user_input,
            ),
            model=effective_model,
            registry=self._registry,
            conversation=effective_context,
            middlewares=self._middlewares,
            search=self.search,
            sandbox=self.sandbox,
            workflows=self.workflows,
            state=self.state,
            flow=flow,
        )

        # ── PREPARE ──
        await self._prepare.run(ctx)

        try:
            # 플로우 모드
            if ctx.flow is not None:
                async for event in self._run_flow(ctx):
                    yield event
                return

            for iteration in range(self.max_iterations):
                ctx.iteration = iteration + 1

                yield {
                    "type": "thinking",
                    "data": {
                        "iteration": ctx.iteration,
                        "tools_count": len(ctx.tools),
                    },
                }

                # ── RESOLVE ──
                try:
                    resolve_result = await self._resolve.run(ctx)
                except Exception as e:
                    yield {
                        "type": "error",
                        "data": {"error": str(e), "resumable": True},
                    }
                    return

                response = resolve_result.data.get("response")
                if response is None:
                    yield {"type": "error", "data": "RESOLVE에서 response 없음"}
                    return

                # 종료 조건
                if not response.has_tool_calls:
                    ctx.final_text = response.text or ""
                    ctx.conversation.add_assistant(content=ctx.final_text)
                    yield {"type": "done", "data": ctx.final_text}
                    return

                # ── ACT ──
                ctx.pending_events.clear()
                await self._act.execute(ctx, response)

                for event in ctx.pending_events:
                    yield event

                # ── OBSERVE ──
                await self._observe.run(ctx)

            # MAX_ITERATIONS 초과
            ctx.final_text = "[오류] 최대 실행 횟수를 초과했습니다."
            logger.warning("Executor '%s' 최대 반복(%d) 초과", self.name, self.max_iterations)
            yield {"type": "error", "data": ctx.final_text}

        finally:
            # cleanup
            for mw in ctx.middlewares:
                await mw.on_end(ctx.run_ctx, ctx.final_text)

            # extra_tools 세션 정리
            if extra_tools:
                self._registry.cleanup_session(session_id)

            # state 최종 저장
            if ctx.state is not None:
                try:
                    await ctx.state.save(ctx.session_id, {
                        "final_text": ctx.final_text,
                        "completed": True,
                    })
                except Exception:
                    pass

    # ─── 플로우 모드 ───

    async def _run_flow(self, ctx: ExecutionContext) -> AsyncIterator[dict]:
        """FlowState 기반 논리적 흐름 실행."""
        import asyncio
        from mantis.executor.flow import FlowState

        flow: FlowState = ctx.flow

        while not flow.is_done:
            step = flow.current_step()

            yield {
                "type": "flow_step",
                "data": {"step_id": step.id, "type": step.type},
            }

            if step.type == "tool":
                args = flow.resolve_args(step)
                # 미들웨어 on_before_tool
                block_reason = None
                for mw in ctx.middlewares:
                    _, args, block_reason = await mw.on_before_tool(
                        ctx.run_ctx, step.tool, args,
                    )
                    if block_reason:
                        break

                if block_reason:
                    yield {"type": "blocked", "data": {"tool": step.tool, "reason": block_reason}}
                    flow.step_results[step.id] = {"error": f"blocked: {block_reason}"}
                else:
                    try:
                        result = await ctx.registry.execute(
                            {"name": step.tool, "arguments": args},
                            session_id=ctx.session_id,
                        )
                        if "error" in result:
                            flow.step_results[step.id] = {"error": result["error"]}
                            yield {"type": "tool_error", "data": {"name": step.tool, "error": result["error"]}}
                        else:
                            flow.step_results[step.id] = result.get("result", result)
                            yield {"type": "tool_result", "data": {"name": step.tool, "result": result}}
                        # 미들웨어 on_after_tool
                        for mw in ctx.middlewares:
                            await mw.on_after_tool(ctx.run_ctx, step.tool, args, result)
                    except Exception as e:
                        logger.exception("플로우 도구 '%s' 실행 실패", step.tool)
                        flow.step_results[step.id] = {"error": str(e)}
                        yield {"type": "tool_error", "data": {"name": step.tool, "error": str(e)}}

                flow.advance()

            elif step.type == "condition":
                # N-way 분기 (branches dict) 또는 이진 분기 (then/else)
                if step.branches:
                    value = flow.evaluate_condition_value(step.condition)
                    value_str = str(value) if value is not None else ""
                    target = step.branches.get(value_str, step.else_step)
                    # 선택되지 않은 브랜치 전부 skip
                    for branch_target in step.branches.values():
                        if branch_target != target:
                            flow.skip(branch_target)
                    if step.else_step and step.else_step != target:
                        flow.skip(step.else_step)
                    flow.step_results[step.id] = {
                        "condition": step.condition,
                        "value": value_str,
                        "next": target,
                    }
                    yield {
                        "type": "condition_result",
                        "data": {"condition": step.condition, "value": value_str, "next": target},
                    }
                else:
                    taken = flow.evaluate_condition(step.condition)
                    target = step.then_step if taken else step.else_step
                    skipped = step.else_step if taken else step.then_step
                    if skipped:
                        flow.skip(skipped)
                    flow.step_results[step.id] = {
                        "condition": step.condition,
                        "result": taken,
                        "next": target,
                    }
                    yield {
                        "type": "condition_result",
                        "data": {"condition": step.condition, "result": taken, "next": target},
                    }
                flow.advance(target)

            elif step.type == "agent":
                # 에이전트 서브루프 — 중간 이벤트를 상위로 스트리밍
                sub_result = ""
                async for sub_event in self._stream_flow_agent(ctx, step):
                    if sub_event["type"] == "agent_done":
                        sub_result = sub_event["data"]
                    else:
                        yield sub_event
                flow.step_results[step.id] = sub_result
                yield {"type": "agent_result", "data": {"step_id": step.id, "result": sub_result}}
                flow.advance()

            elif step.type == "parallel":
                tasks = []
                parallel_steps = {s.id: s for s in flow.steps}
                for ps_id in step.parallel_steps:
                    ps = parallel_steps.get(ps_id)
                    if ps and ps.type == "tool":
                        args = flow.resolve_args(ps)
                        tasks.append(self._execute_flow_tool_task(ctx, ps, args))

                results = await asyncio.gather(*tasks, return_exceptions=True)
                parallel_results = {}
                for ps_id, res in zip(step.parallel_steps, results):
                    if isinstance(res, Exception):
                        parallel_results[ps_id] = {"error": str(res)}
                    else:
                        parallel_results[ps_id] = res

                flow.step_results[step.id] = parallel_results
                yield {"type": "parallel_result", "data": parallel_results}
                flow.advance()

            elif step.type == "provider":
                # 설정 객체를 생성하여 step_results에 저장.
                # 하위 스텝이 args_from으로 참조.
                config = dict(step.config) if step.config else {}
                config["_provider_type"] = step.provider_type or "config"
                flow.step_results[step.id] = config
                yield {
                    "type": "flow_step",
                    "data": {"step_id": step.id, "type": "provider", "provider_type": step.provider_type},
                }
                flow.advance()

            elif step.type == "stream":
                # source_step의 결과를 target_step으로 스트리밍 전달.
                # Generator면 청크 단위로 전파, 아니면 그대로 전달.
                source_data = flow.step_results.get(step.source_step)
                if hasattr(source_data, "__iter__") and not isinstance(source_data, (str, dict, list)):
                    # Generator/Iterator — 청크 수집하면서 이벤트 전파
                    chunks = []
                    for chunk in source_data:
                        chunks.append(chunk)
                        yield {"type": "stream_chunk", "data": {"step_id": step.id, "chunk": chunk}}
                    flow.step_results[step.id] = "".join(str(c) for c in chunks)
                else:
                    flow.step_results[step.id] = source_data
                flow.advance()

            else:
                yield {"type": "error", "data": f"알 수 없는 스텝 타입: {step.type}"}
                return

        # 플로우 완료
        import json
        try:
            ctx.final_text = json.dumps(flow.step_results, ensure_ascii=False, default=str)
        except (TypeError, ValueError):
            ctx.final_text = str(flow.step_results)
        yield {"type": "done", "data": flow.step_results}

    async def _stream_flow_agent(
        self, ctx: ExecutionContext, step,
    ) -> AsyncIterator[dict]:
        """agent 스텝 — 중간 이벤트를 스트리밍하면서 서브 에이전트 실행.

        thinking, tool_call, tool_result 등 중간 이벤트는
        step_id를 태깅하여 상위 플로우로 전파한다.
        최종 결과는 agent_done 이벤트로 반환.
        """
        sub_context = ConversationContext(system_prompt=self.system_prompt)
        prompt = step.prompt or ""

        # 이전 스텝 결과를 컨텍스트에 주입
        if ctx.flow and ctx.flow.step_results:
            context_text = "\n".join(
                f"{k}: {v}" for k, v in ctx.flow.step_results.items()
            )
            sub_context.inject_context(f"이전 스텝 결과:\n{context_text}")

        # step.tools가 지정되면 해당 도구만 extra_tools로 전달
        extra_tools = None
        if step.tools:
            extra_tools = []
            for tool_name in step.tools:
                spec = ctx.registry.get(tool_name, session_id=ctx.session_id)
                if spec:
                    extra_tools.append(spec)

        sub_context.add_user(prompt)

        result = ""
        sub_loop = self._run_loop(
            prompt, session_id=ctx.session_id,
            context=sub_context, extra_tools=extra_tools,
        )
        try:
            async for event in sub_loop:
                if event["type"] == "done":
                    result = event["data"]
                    yield {"type": "agent_done", "data": result}
                    return
                if event["type"] == "error":
                    result = str(event["data"])
                    yield {"type": "agent_done", "data": result}
                    return
                # 중간 이벤트는 step_id 태깅하여 상위로 전파
                event.setdefault("data", {})
                if isinstance(event.get("data"), dict):
                    event["data"]["agent_step_id"] = step.id
                yield event
        finally:
            await sub_loop.aclose()
        # 서브루프가 이벤트 없이 종료된 경우
        yield {"type": "agent_done", "data": result}

    async def _execute_flow_tool_task(self, ctx: ExecutionContext, step, args: dict) -> Any:
        """병렬 실행용 도구 태스크."""
        result = await ctx.registry.execute(
            {"name": step.tool, "arguments": args},
            session_id=ctx.session_id,
        )
        return result.get("result", result)

    # ─── 공개 API ───

    async def run(
        self,
        input: str,
        *,
        session_id: str | None = None,
        model: Any | None = None,
        context: ConversationContext | None = None,
        extra_tools: list[Any] | None = None,
        flow: Any | None = None,
    ) -> str:
        """입력 → 최종 텍스트 응답.

        플로우 모드에서 dict 결과가 필요하면 run_flow()를 사용하세요.
        """
        import json as _json

        result = ""
        loop = self._run_loop(
            input, session_id,
            model=model, context=context, extra_tools=extra_tools, flow=flow,
        )
        try:
            async for event in loop:
                if event["type"] == "done":
                    data = event["data"]
                    if isinstance(data, str):
                        result = data
                    else:
                        result = _json.dumps(data, ensure_ascii=False, default=str)
                    break
                if event["type"] == "error":
                    data = event["data"]
                    if isinstance(data, dict) and "error" in data:
                        raise LLMError(data["error"])
                    result = data if isinstance(data, str) else ""
                    break
        finally:
            await loop.aclose()
        return result

    async def run_flow(
        self,
        input: str,
        flow: Any,
        *,
        session_id: str | None = None,
        model: Any | None = None,
        context: ConversationContext | None = None,
        extra_tools: list[Any] | None = None,
    ) -> dict[str, Any]:
        """플로우 모드 전용 — 입력 → 스텝별 결과 dict 반환."""
        result: dict[str, Any] = {}
        loop = self._run_loop(
            input, session_id,
            model=model, context=context, extra_tools=extra_tools, flow=flow,
        )
        try:
            async for event in loop:
                if event["type"] == "done":
                    data = event["data"]
                    result = data if isinstance(data, dict) else {"result": data}
                    break
                if event["type"] == "error":
                    data = event["data"]
                    if isinstance(data, dict) and "error" in data:
                        raise LLMError(data["error"])
                    result = {"error": data if isinstance(data, str) else str(data)}
                    break
        finally:
            await loop.aclose()
        return result

    async def run_stream(
        self,
        input: str,
        *,
        session_id: str | None = None,
        model: Any | None = None,
        context: ConversationContext | None = None,
        extra_tools: list[Any] | None = None,
        flow: Any | None = None,
    ) -> AsyncIterator[dict]:
        """입력 → 실행 이벤트 스트림."""
        async for event in self._run_loop(
            input, session_id,
            model=model, context=context, extra_tools=extra_tools, flow=flow,
        ):
            yield event
